                        style='font-size:11.0pt;font-family:"Times New Roman",serif'>${match[2]}</span></p>`;
                    }
                    // 1., 2., 3. (Nivel 2 - Decimales)
                    else if (match = trimmedLine.match(/^(\d+\.)\s*(.*)/)) {
